mapper.select:
SELECT * FROM leave_application
WHERE employee_id = #{employeeId}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT * FROM leave_application
WHERE employee_id = #{employeeId}
  AND status = 2  
  AND start_date <= #{endDate}
  AND end_date >= #{startDate}
ORDER BY start_date ASC

SELECT * FROM leave_application
WHERE status = #{status}
ORDER BY create_time DESC
LIMIT #{offset}, #{limit}

SELECT COALESCE(SUM(days), 0)
FROM leave_application
WHERE employee_id = #{employeeId}
  AND leave_type = #{leaveType}
  AND status = 2  
  AND start_date <= #{endDate}
  AND end_date >= #{startDate}

SELECT
    leave_type AS leaveType,
    COALESCE(SUM(days), 0) AS totalDays,
    COUNT(*) AS count
FROM leave_application
WHERE employee_id = #{employeeId}
  AND status = 2
  AND start_date <= #{monthEnd}
  AND end_date >= #{monthStart}
GROUP BY leave_type

SELECT la.leave_type AS leaveType, COALESCE(SUM(la.days), 0) AS totalDays, COUNT(*) AS count FROM leave_application la JOIN employee e ON la.employee_id = e.id WHERE la.status = 2 AND la.start_date <= #{monthEnd} AND la.end_date >= #{monthStart}
AND e.dept_id = #{deptId}
GROUP BY la.leave_type

SELECT COALESCE(SUM(la.days), 0)
FROM leave_application la
JOIN employee e ON la.employee_id = e.id
WHERE e.dept_id = #{deptId}
  AND la.status = 2
  AND la.start_date <= #{monthEnd}
  AND la.end_date >= #{monthStart}
